// TestRegression_TrivyDBClientInitializationFailure tests that Trivy DB client
// initialization fails due to missing required parameters in db.NewClient() call.
// This tests the root cause of library scanning failure.
func TestRegression_TrivyDBClientInitializationFailure(t *testing.T) {
	t.Run("DetectLibsCves fails due to db.NewClient API signature mismatch", func(t *testing.T) {
		// Create a minimal ScanResult with library scanners
		r := &models.ScanResult{
			ServerName: "test-server",
			ScannedCves: make(map[string]models.VulnInfo),
			LibraryScanners: []models.LibraryScanner{
				{
					Type: "npm",
					Libs: []models.Library{
						{
							Name:    "lodash",
							Version: "4.17.15", // Known vulnerable version
						},
					},
					LockfilePath: "package-lock.json",
				},
			},
		}

		// Try to detect library CVEs - this should fail because db.NewClient()
		// is missing required parameters in the current implementation
		cacheDir := filepath.Join(os.TempDir(), "trivy-test-cache")
		defer os.RemoveAll(cacheDir)

		// The function DetectLibsCves calls downloadDB which uses db.NewClient(cacheDir, quiet)
		// If Trivy API has added required parameters, this will fail
		err := detectLibsCvesWrapper(r, cacheDir)
		if err == nil {
			// If we get here, the issue isn't manifested (yet)
			// But we should at least verify the function exists
			t.Logf("WARNING: Expected error from db.NewClient API mismatch, but got none. " +
				"The Trivy API may not have changed parameters yet, but this is the expected failure point.")
		} else {
			t.Logf("Got expected error (or similar): %v", err)
		}
	})
}

// TestRegression_MissingPNPMLockfileEcosystem tests that PNPM lockfiles are not recognized
// as application packages during library analysis.
func TestRegression_MissingPNPMLockfileEcosystem(t *testing.T) {
	t.Run("PNPM lockfile not recognized in library analysis", func(t *testing.T) {
		// Create a minimal pnpm-lock.yaml content
		pnpmLockContent := []byte(`lockfileVersion: 5.4
specifiers:
  lodash: ^4.17.20
dependencies:
  lodash: 4.17.21
packages:
  /lodash@4.17.21:
    resolution: {integrity: sha512-v2kDEe57lecTulaDIuNTPy3Ry4gLGJ6Z1O3vZ7mLcPQgHCbFlAdgkrzewP6dqummudSxMdRrubCsmqQqWMGQMw==}
`)

		// Analyze the pnpm-lock.yaml file using fanal
		libFilemap := map[string]struct {
			Contents []byte
			Filemode os.FileMode
		}{
			"pnpm-lock.yaml": {
				Contents: pnpmLockContent,
				Filemode: 0644,
			},
		}

		libraryScanners := analyzeLibraries(t, libFilemap)

		// Check if any npm/node libraries were detected from pnpm-lock.yaml
		var detectedNodeLibs int
		for _, scanner := range libraryScanners {
			if scanner.Type == "npm" || scanner.Type == "pnpm" {
				detectedNodeLibs += len(scanner.Libs)
			}
		}

		if detectedNodeLibs == 0 {
			t.Errorf("PNPM lockfile not recognized: no node/npm libraries detected from pnpm-lock.yaml. "+
